@@ -126,0 +126,8 @@
+static uint64_t check_feature(uint64_t hwcap, uint64_t feature_bit_mask, uint64_t hwcap_bitmask) {
+  if (hwcap & hwcap_bitmask) {
+    return feature_bit_mask;
+  } else {
+    return 0;
+  }
+}
